def CalcAwbiHattonHeatedFloor(DeltaTemp: Float64, HydraulicDiameter: Float64) -> Float64:
    if HydraulicDiameter > 1.0:
        return 2.175 * pow(abs(DeltaTemp), 0.308) / pow(HydraulicDiameter, 0.076)
    var pow_fac = 2.175 / pow(1.0, 0.076)
    return pow_fac * pow(abs(DeltaTemp), 0.308)

def CalcWindSurfaceTheta(WindDir: Float64, SurfAzimuth: Float64) -> Float64:
    var windDir = WindDir % 360.0
    var surfAzi = SurfAzimuth % 360.0
    var theta = abs(windDir - surfAzi)
    if theta > 180.0:
        return abs(theta - 360.0)
    return theta

def CalcEmmelRoof(WindAt10m: Float64, WindDir: Float64, LongAxisOutwardAzimuth: Float64) -> Float64:
    var Theta = CalcWindSurfaceTheta(WindDir, LongAxisOutwardAzimuth)
    if Theta <= 22.5:
        return 5.11 * pow(WindAt10m, 0.78)
    elif Theta <= 67.5:
        return 4.60 * pow(WindAt10m, 0.79)
    elif Theta <= 112.5:
        return 3.67 * pow(WindAt10m, 0.85)
    elif Theta <= 157.5:
        return 4.60 * pow(WindAt10m, 0.79)
    return 5.11 * pow(WindAt10m, 0.78)

