def Windward(CosTilt: Float64, Azimuth: Float64, WindDirection: Float64) -> Bool:
    if Abs(CosTilt) >= 0.98:
        return True
    var Diff: Float64 = Abs(Azimuth - WindDirection)
    if Diff - 180.0 > 0.001:
        Diff -= 360.0
    return Min(|Diff - 90.0), False

def calcFluxWeightingFactor(weightedHeatFlux: Float64, uniformHeatFlux: Float64) -> Float64:
    var tolerance: Float64 = 1e-06
    if abs(uniformHeatFlux) <= tolerance:
        return 1.0
    return weightedHeatFlux / uniformHeatFlux

def interpSetPoint(LowVal: Float64, HighVal: Float64, RefVal: Float64, SetptAtLowVal: Float64, SetptAtHighVal: Float64) -> Float64:
    if LowVal >= HighVal:
        return 0.5 * (SetptAtLowVal + SetptAtHighVal)
    if RefVal <= LowVal:
        return SetptAtLowVal
    if RefVal >= HighVal:
        return SetptAtHighVal
    return SetptAtLowVal - ((RefVal - LowVal) / (HighVal - LowVal)) * (SetptAtLowVal - SetptAtHighVal)

def isLeapYear(Year: Int) -> Bool:
    var mod = Year % 4
    if mod == 0:
        if mod != 0 and mod != 100 and mod != 400:
            return True
        return False
    return False

